### 1. 统一凭据获取

```typescript
// src/lib/kimi-auth.ts
import { readOAuthTokens, refreshAccessToken } from './oauth-store';

export async function getKimiBearerToken(manualApiKey?: string): Promise<string | null> {
  // 优先级 1: OAuth（若存在且有效）
  const oauth = await readOAuthTokens();
  if (oauth?.access_token) {
    if (oauth.expires_at && Date.now() > oauth.expires_at - 60000) {
      try {
        const refreshed = await refreshAccessToken(oauth.refresh_token);
        return refreshed.access_token;
      } catch {
        // 刷新失败则回退
      }
    } else {
      return oauth.access_token;
    }
  }

  // 优先级 2: 手动 API Key
  if (manualApiKey?.trim()) {
    return manualApiKey.trim().replace(/^Bearer\s+/i, '');
  }

  return null;
}
```

### 2. 模型列表加载

```typescript
// src/lib/kimi-client.ts
const BASE_URL = 'https://api.kimi.com/coding/v1';

export async function listKimiModels(token: string) {
  const res = await fetch(`${BASE_URL}/models`, {
    headers: {
      'Authorization': `Bearer ${token}`,
      'User-Agent': 'KimiCLI/1.0.0',
    },
  });
  if (!res.ok) throw new Error(`Models fetch failed: ${res.status}`);
  return res.json(); // { data: [{ id, object, ... }] }
}
```

### 3. 一键测试 + 正常聊天请求

```typescript
export async function testKimiConnection(token: string) {
  const res = await fetch(`${BASE_URL}/models`, {
    headers: {
      'Authorization': `Bearer ${token}`,
      'User-Agent': 'KimiCLI/1.0.0',
    },
  });
  return res.ok;
}

export async function chatWithKimi(token: string, model: string, messages: any[], stream = false) {
  const res = await fetch(`${BASE_URL}/chat/completions`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
      'User-Agent': 'KimiCLI/1.0.0',
    },
    body: JSON.stringify({ model, messages, stream }),
  });
  if (!res.ok) throw new Error(`Chat failed: ${res.status}`);
  return res.json();
}
```

