const BASE_URL = 'https://api.kimi.com/coding/v1';
const TOKEN = process.env.KIMI_TOKEN || 'your-token-here';

async function test() {
  console.log('Testing Kimi Code API...');
  const r1 = await fetch(`${BASE_URL}/models`, {
    headers: { 'Authorization': `Bearer ${TOKEN}`, 'User-Agent': 'KimiCLI/1.0.0' }
