  console.log('Models status:', r1.status);
  if (r1.ok) console.log('Models:', Object.keys(await r1.json()));

  const r2 = await fetch(`${BASE_URL}/chat/completions`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${TOKEN}`, 'Content-Type': 'application/json', 'User-Agent': 'KimiCLI/1.0.0' },
    body: JSON.stringify({ model: 'kimi-for-coding', messages: [{ role: 'user', content: 'hi' }] })
  });
